# Dict fundamentals -- tool registry and tool result storage
from typing import Callable, Any

# Creation styles
config: dict[str, Any] = {"max_retries": 3, "timeout": 30, "model": "claude-opus-4-5"}
config2 = dict(max_retries=3, timeout=30)           # keyword-arg form
config3 = dict(zip(["a","b"], [1, 2]))              # from parallel iterables

# Safe access -- .get() never raises KeyError
limit = config.get("max_retries", 3)               # returns 3 if key missing
model = config.get("model")                        # returns None if missing

# Conditional update -- only set if not already present
config.setdefault("temperature", 0.7)

# Merge dicts (Python 3.9+)
overrides = {"timeout": 60, "stream": True}
full_config = config | overrides                   # new dict
config |= overrides                                # in-place

# Dict as tool registry
tool_registry: dict[str, Callable] = {}

def register(name: str):
    def decorator(fn: Callable) -> Callable:
        tool_registry[name] = fn
        return fn
    return decorator

@register("search")
def search(query: str) -> list[str]:
    return []  # implementation omitted

@register("run_code")
def run_code(code: str) -> str:
    return ""

# Iterate items
for tool_name, fn in tool_registry.items():
    print(f"{tool_name}: {fn.__doc__}")

# Dict comprehension -- transform tool result map
results: dict[str, Any] = {"call_001": {"data": [1]}, "call_002": {"data": [2]}}
data_only = {k: v["data"] for k, v in results.items()}  # {"call_001": [1], ...}

# Nested access pattern
step = {"tool": "search", "args": {"q": "python"}, "result": {"hits": 5}}
hits = step.get("result", {}).get("hits", 0)      # safe two-level access

# Set fundamentals -- deduplication and permission management

# Build from iterable -- duplicates silently dropped
allowed_tools: set[str] = {"search", "calculator", "browser", "search"}  # len == 3

# O(1) membership -- use set, not list, for repeated checks
if "search" in allowed_tools:
    print("search is available")

# add / discard / remove
allowed_tools.add("code_runner")
allowed_tools.discard("browser")   # no error if absent
allowed_tools.remove("calculator") # raises KeyError if absent

# Set algebra -- compute permission diff between agent versions
old_perms: set[str] = {"read_file", "write_file", "delete_file", "run_code"}
new_perms: set[str] = {"read_file", "write_file", "run_code", "web_fetch"}

added   = new_perms - old_perms    # {"web_fetch"}
removed = old_perms - new_perms    # {"delete_file"}
kept    = old_perms & new_perms    # {"read_file", "write_file", "run_code"}

# URL frontier for web crawl agent
visited: set[str] = set()
queue: list[str] = ["https://example.com"]

while queue:
    url = queue.pop(0)
    if url in visited:           # O(1)
        continue
    visited.add(url)
    # ... fetch and process url ...

# frozenset as dict key (cache key for a capability tuple)
cap_key: frozenset[str] = frozenset({"search", "run_code"})
capability_cache: dict[frozenset[str], list[str]] = {}
capability_cache[cap_key] = ["allowed to search and execute code"]

from __future__ import annotations
import copy
from typing import Any, Callable

class AgentState:
    """Holds all runtime state for a single agent run."""

    def __init__(self, system_prompt: str, allowed_tools: set[str]) -> None:
        # list: ordered, mutable -- conversation history
        self.messages: list[dict[str, str]] = [
            {"role": "system", "content": system_prompt}
        ]
        # set: O(1) membership, dedup -- which tools this agent may call
        self.allowed_tools: set[str] = set(allowed_tools)   # copy on construction
        # dict: key->value -- registered tool implementations
        self.tool_registry: dict[str, Callable[..., Any]] = {}
        # dict: key->value -- all tool call results keyed by call ID
        self.tool_results: dict[str, Any] = {}
        # tuple: immutable record -- fixed routing metadata
        self.route: tuple[str, str] = ("planner", "executor")

    def add_message(self, role: str, content: str) -> None:
        self.messages.append({"role": role, "content": content})

    def register_tool(self, name: str, fn: Callable[..., Any]) -> None:
        if name not in self.allowed_tools:
            raise ValueError(f"{name!r} is not in the allowed tool set")
        self.tool_registry[name] = fn

    def record_result(self, call_id: str, result: Any) -> None:
        self.tool_results[call_id] = result

    def recent_context(self, n: int = 10) -> list[dict[str, str]]:
        """Return last n turns without mutating history."""
        return self.messages[-n:]          # slice creates new list -- safe

    def snapshot(self) -> AgentState:
        """Deep-copy for sub-agent isolation."""
        return copy.deepcopy(self)

# Usage
state = AgentState(
    system_prompt="You are a research assistant.",
    allowed_tools={"search", "summarise", "cite"}
)
state.register_tool("search", lambda q: [])  # stub
state.add_message("user", "Find papers on RAG.")
state.record_result("call_001", {"hits": 5, "docs": []})
print(state.recent_context(5))

from __future__ import annotations
from dataclasses import dataclass

@dataclass
class Chunk:
    chunk_id: str
    source: str
    text: str
    score: float

class RAGPipeline:
    def __init__(self, max_chunks: int = 5, disallowed_sources: set[str] | None = None) -> None:
        self.max_chunks = max_chunks
        # set for O(1) membership check
        self.disallowed: set[str] = disallowed_sources or set()
        # dict: chunk_id -> Chunk (dedup by ID, keep highest score)
        self._seen: dict[str, Chunk] = {}

    def add_chunks(self, chunks: list[Chunk]) -> None:
        for c in chunks:
            if c.source in self.disallowed:
                continue
            existing = self._seen.get(c.chunk_id)
            if existing is None or c.score > existing.score:
                self._seen[c.chunk_id] = c

    def top_chunks(self) -> list[Chunk]:
        """Return up to max_chunks sorted by descending score."""
        ranked: list[Chunk] = sorted(
            self._seen.values(),
            key=lambda c: c.score,
            reverse=True
        )
        return ranked[: self.max_chunks]

    def to_context(self) -> str:
        parts: list[str] = []
        for c in self.top_chunks():
            cid, src, txt = c.chunk_id, c.source, c.text
            parts.append(f"[{cid} | {src}]\n{txt}")
        return "\n\n".join(parts)

pipe = RAGPipeline(max_chunks=3, disallowed_sources={"spam-site.com"})
pipe.add_chunks([
    Chunk("c1", "arxiv.org", "RAG improves grounding...", 0.92),
    Chunk("c2", "spam-site.com", "Buy now...", 0.99),
    Chunk("c1", "arxiv.org", "RAG improves grounding...", 0.95),
    Chunk("c3", "papers.org", "Dense retrieval uses...", 0.88),
])
print(pipe.to_context())
